SELECT COUNT(*) AS NumberOfHighSeverityBreaches
FROM breach_reports
WHERE severity_id = (SELECT severity_id FROM severity_levels WHERE severity_name = 'High');

SELECT title, breach_date
FROM breach_reports
ORDER BY breach_date;

SELECT dt.data_type_name, dt.description, dt.sensitivity_level
FROM data_types dt
INNER JOIN breach_data_types bdt ON dt.data_type_id = bdt.data_type_id
WHERE bdt.report_id = (
    SELECT report_id FROM breach_reports WHERE title = 'CA agency reports ADAP data breach'
);

SELECT *
FROM breach_reports
ORDER BY breach_date DESC;
